const INITIAL_APPLICATIONS = [{"id":"90c8bcc1-02a4-4c44-becf-fba3ba88f71e","createdAt":"2026-06-12T11:02:12.709Z","programTitle":"1:1 맞춤형 컨설팅","programPath":"/content/11맞춤형컨설팅/","status":"확정","applicantType":"학생","consultantId":"andong3","consultantName":"김재형소장","place":"일광교육행복타운 4층(진학상담실)","date":"2026-06-12","time":"13:00","residence":"기장읍","studentName":"q","parentPhone":"000-0000-0000","studentPhone":"000-0000-0000","school":"q","grade":"q","password":"1","content":"지원희망대학:\n희망학과:\n상담희망내용:","memo":""},{"id":"97b90a8a-2916-4f95-aa2e-385b199e2fb4","createdAt":"2026-06-12T11:02:09.839Z","programTitle":"1:1 맞춤형 컨설팅","programPath":"/content/11맞춤형컨설팅/","status":"취소","applicantType":"학생","consultantId":"andong3","consultantName":"김재형소장","place":"일광교육행복타운 4층(진학상담실)","date":"2026-06-12","time":"13:00","residence":"기장읍","studentName":"q","parentPhone":"000-0000-0000","studentPhone":"000-0000-0000","school":"q","grade":"q","password":"1","content":"지원희망대학:\n희망학과:\n상담희망내용:","memo":""}];

const KEY_SITE = "gijang_static_site";
const KEY_USERS = "gijang_static_users";
const KEY_APPLICATIONS = "gijang_static_applications";
const KEY_SESSION = "gijang_static_session";

function clone(value) { return JSON.parse(JSON.stringify(value)); }
function loadJson(key, fallback) {
  try {
    const raw = localStorage.getItem(key);
    return raw ? JSON.parse(raw) : clone(fallback);
  } catch {
    return clone(fallback);
  }
}
function saveJson(key, value) {
  try { localStorage.setItem(key, JSON.stringify(value)); } catch {}
}
let site = loadJson(KEY_SITE, INITIAL_SITE);
let users = loadJson(KEY_USERS, INITIAL_USERS);
let applications = loadJson(KEY_APPLICATIONS, INITIAL_APPLICATIONS);
let session = loadJson(KEY_SESSION, null);

const DB_CONFIG = globalThis.GIJANG_DB_CONFIG || {};
const SUPABASE_CONFIG = DB_CONFIG.supabase || {};
const REMOTE_TABLE = SUPABASE_CONFIG.table || "app_state";
const EDGE_FUNCTION = SUPABASE_CONFIG.functionName || "";
const AUTH_EMAIL_DOMAIN = SUPABASE_CONFIG.authEmailDomain || "gijang.local";
const EDGE_ENABLED = Boolean(SUPABASE_CONFIG.url && SUPABASE_CONFIG.anonKey && EDGE_FUNCTION);
const REST_ENABLED = Boolean(SUPABASE_CONFIG.url && SUPABASE_CONFIG.anonKey && !EDGE_FUNCTION);
const REMOTE_ENABLED = EDGE_ENABLED || REST_ENABLED;
let remoteReady = false;
let remoteLoading = false;
let remoteError = "";
let remoteQueue = Promise.resolve();

function supabaseBaseUrl() {
  return String(SUPABASE_CONFIG.url || "").replace(new RegExp("/+$"), "");
}
function supabaseHeaders(extra = {}) {
  return {
    "apikey": SUPABASE_CONFIG.anonKey,
    "Authorization": "Bearer " + SUPABASE_CONFIG.anonKey,
    "Content-Type": "application/json",
    ...extra
  };
}
function loginIdToEmail(id = "") {
  const value = String(id || "").trim();
  return value.includes("@") ? value : value + "@" + AUTH_EMAIL_DOMAIN;
}
function authToken() {
  return session?.accessToken || "";
}
async function callEdge(action, payload = {}, options = {}) {
  const url = supabaseBaseUrl() + "/functions/v1/" + encodeURIComponent(EDGE_FUNCTION);
  const token = options.token || (options.auth ? authToken() : "");
  const headers = {
    "apikey": SUPABASE_CONFIG.anonKey,
    "Content-Type": "application/json"
  };
  if (token) headers.Authorization = "Bearer " + token;
  const response = await fetch(url, {
    method: "POST",
    headers,
    body: JSON.stringify({ action, payload })
  });
  const text = await response.text();
  const data = text ? JSON.parse(text) : {};
  if (!response.ok || data.error) throw new Error(data.error || "Edge Function failed: " + response.status);
  return data;
}
async function signInWithSupabaseAuth(loginId, password) {
  const response = await fetch(supabaseBaseUrl() + "/auth/v1/token?grant_type=password", {
    method: "POST",
    headers: supabaseHeaders(),
    body: JSON.stringify({ email: loginIdToEmail(loginId), password })
  });
  const data = await response.json();
  if (!response.ok) throw new Error(data.error_description || data.msg || "아이디 또는 비밀번호를 확인해주세요.");
  const profile = await callEdge("me", {}, { token: data.access_token });
  if (Array.isArray(profile.users)) {
    users = profile.users;
    saveJson(KEY_USERS, users);
    site.form = site.form || {};
    site.form.consultants = users.filter((user) => user.role === "consultant").map((user) => ({ id: user.id, name: user.name }));
    saveJson(KEY_SITE, site);
  }
  return {
    id: profile.user.id,
    authUserId: profile.user.authUserId,
    role: profile.user.role,
    name: profile.user.name,
    accessToken: data.access_token,
    refreshToken: data.refresh_token,
    expiresAt: Date.now() + ((data.expires_in || 3600) * 1000)
  };
}
async function fetchRemoteState(key, fallback) {
  const url = supabaseBaseUrl() + "/rest/v1/" + encodeURIComponent(REMOTE_TABLE) + "?key=eq." + encodeURIComponent(key) + "&select=value&limit=1";
  const response = await fetch(url, { headers: supabaseHeaders() });
  if (!response.ok) throw new Error("Supabase read failed: " + response.status);
  const rows = await response.json();
  return rows[0]?.value ?? clone(fallback);
}
async function upsertRemoteState(key, value) {
  const url = supabaseBaseUrl() + "/rest/v1/" + encodeURIComponent(REMOTE_TABLE) + "?on_conflict=key";
  const response = await fetch(url, {
    method: "POST",
    headers: supabaseHeaders({ "Prefer": "resolution=merge-duplicates,return=minimal" }),
    body: JSON.stringify({ key, value, updated_at: new Date().toISOString() })
  });
  if (!response.ok) throw new Error("Supabase write failed: " + response.status);
}
function persistRemoteState(key, value) {
  if (!REMOTE_ENABLED) return;
  const snapshot = clone(value);
  remoteQueue = remoteQueue.then(() => {
    if (EDGE_ENABLED) {
      if (key === "site") return callEdge("saveSite", { site: snapshot }, { auth: true });
      if (key === "users") return callEdge("saveUsers", { users: snapshot, authEmailDomain: AUTH_EMAIL_DOMAIN }, { auth: true }).then((data) => {
        users = data.users || users;
        saveJson(KEY_USERS, users);
      });
      return Promise.resolve();
    }
    return upsertRemoteState(key, snapshot);
  }).then(() => {
    remoteReady = true;
    remoteError = "";
  }).catch((error) => {
    remoteError = error.message || "Supabase 저장에 실패했습니다.";
    console.error(error);
  });
}
async function loadRemoteData() {
  if (!REMOTE_ENABLED) return;
  remoteLoading = true;
  try {
    if (EDGE_ENABLED) {
      const remote = await callEdge("bootstrap", {
        site: INITIAL_SITE,
        applications: INITIAL_APPLICATIONS
      });
      site = remote.site || INITIAL_SITE;
      users = remote.users || [];
      applications = remote.applications || [];
      site.form = site.form || {};
      site.form.consultants = users.filter((user) => user.role === "consultant").map((user) => ({ id: user.id, name: user.name }));
    } else {
      const [remoteSite, remoteUsers, remoteApplications] = await Promise.all([
        fetchRemoteState("site", INITIAL_SITE),
        fetchRemoteState("users", INITIAL_USERS),
        fetchRemoteState("applications", INITIAL_APPLICATIONS)
      ]);
      site = remoteSite;
      users = remoteUsers;
      applications = remoteApplications;
    }
    saveJson(KEY_SITE, site);
    saveJson(KEY_USERS, users);
    saveJson(KEY_APPLICATIONS, applications);
    remoteReady = true;
    remoteError = "";
    if (!EDGE_ENABLED) {
      persistRemoteState("site", site);
      persistRemoteState("users", users);
      persistRemoteState("applications", applications);
    }
  } catch (error) {
    remoteError = error.message || "Supabase 연결에 실패했습니다.";
    console.error(error);
  } finally {
    remoteLoading = false;
  }
}
async function refreshApplicationsFromRemote() {
  if (!REMOTE_ENABLED) return;
  if (EDGE_ENABLED) {
    const remote = await callEdge("listApplications", {}, { auth: true });
    applications = remote.applications || [];
  } else {
    applications = await fetchRemoteState("applications", applications);
  }
  saveJson(KEY_APPLICATIONS, applications);
}
function saveSite() { saveJson(KEY_SITE, site); persistRemoteState("site", site); }
function saveUsers() { saveJson(KEY_USERS, users); persistRemoteState("users", users); }
function saveApplications() { saveJson(KEY_APPLICATIONS, applications); persistRemoteState("applications", applications); }
function saveSession() { saveJson(KEY_SESSION, session); }

function h(value = "") {
  return String(value).replaceAll("&", "&amp;").replaceAll("<", "&lt;").replaceAll(">", "&gt;").replaceAll('"', "&quot;").replaceAll("'", "&#39;");
}
function safeHtml(value = "") { return String(value || ""); }
function normalizePath(pathname = "") {
  if (!pathname || pathname === "/") return "/";
  return pathname.endsWith("/") ? pathname.slice(0, -1) : pathname;
}
function routeHref(path = "/") { return "#" + path; }
function appPath() {
  const raw = decodeURI(location.hash.replace(/^#/, "") || "/");
  const split = raw.split("?");
  return { pathname: split[0] || "/", params: new URLSearchParams(split[1] || "") };
}
function setRoute(path) {
  const nextHash = "#" + path;
  if (location.hash === nextHash) {
    route();
    return;
  }
  location.hash = path;
}
function currentUser() {
  if (!session) return null;
  if (session.authUserId || session.accessToken) {
    return {
      id: session.id,
      authUserId: session.authUserId,
      role: session.role,
      name: session.name
    };
  }
  return users.find((user) => user.id === session.id) || null;
}
function isAdmin() { return currentUser()?.role === "admin"; }
function isConsultant() { return currentUser()?.role === "consultant"; }
function applicationsForCurrentUser() {
  const user = currentUser();
  if (!user) return [];
  if (user.role === "admin") return applications;
  return applications.filter((item) => item.consultantId === user.id);
}
function compactDateTime(date = "", time = "") {
  const parts = String(date).split("-");
  if (parts.length === 3) return parts[0] + parts[1] + " " + parts[2] + (time ? " " + time : "");
  return (date + " " + time).trim();
}
function shortDate(value = "") {
  const date = String(value).includes("T") ? String(value).slice(0, 10) : String(value);
  const parts = date.split("-");
  return parts.length === 3 ? parts[1] + "-" + parts[2] : date;
}
function uuid() {
  if (crypto?.randomUUID) return crypto.randomUUID();
  return "id-" + Date.now() + "-" + Math.random().toString(16).slice(2);
}

