function initPopups() {
  document.querySelectorAll("[data-popup]").forEach((layer) => {
    const id = layer.getAttribute("data-popup");
    let hiddenUntil = 0;
    try { hiddenUntil = Number(localStorage.getItem("hide_" + id) || 0); } catch {}
    layer.hidden = hiddenUntil > Date.now();
  });
  document.querySelectorAll("[data-popup-close]").forEach((button) => button.addEventListener("click", () => {
    const layer = document.querySelector('[data-popup="' + button.dataset.popupClose + '"]');
    if (layer) layer.hidden = true;
  }));
  document.querySelectorAll("[data-popup-hide]").forEach((button) => button.addEventListener("click", () => {
    try { localStorage.setItem("hide_" + button.dataset.popupHide, String(Date.now() + 24 * 60 * 60 * 1000)); } catch {}
    const layer = document.querySelector('[data-popup="' + button.dataset.popupHide + '"]');
    if (layer) layer.hidden = true;
  }));
}
