function renderLogin() {
  shell("로그인", '<main class="login-bg"><form class="login-card" id="loginForm"><img src="' + h(site.logo) + '" alt="' + h(site.siteName) + '"><h1>로그인</h1><input name="id" placeholder="아이디" required><input name="password" type="password" placeholder="비밀번호" required><button type="submit" class="btn">LOGIN</button><p class="message error" id="loginError"></p></form></main>');
  document.getElementById("loginForm").addEventListener("submit", async (event) => {
    event.preventDefault();
    const data = Object.fromEntries(new FormData(event.currentTarget).entries());
    if (EDGE_ENABLED) {
      try {
        session = await signInWithSupabaseAuth(data.id, data.password);
        saveSession();
        setRoute("/admin");
      } catch (error) {
        document.getElementById("loginError").textContent = error.message || "아이디 또는 비밀번호를 확인해주세요.";
      }
      return;
    }
    const user = users.find((item) => item.id === data.id && item.password === data.password);
    if (!user) {
      document.getElementById("loginError").textContent = "아이디 또는 비밀번호를 확인해주세요.";
      return;
    }
    session = { id: user.id, role: user.role, name: user.name };
    saveSession();
    setRoute("/admin");
  });
}
function adminStorageNote() {
  if (!REMOTE_ENABLED) return "현재 데이터는 이 브라우저에만 저장됩니다. Supabase 설정을 넣으면 여러 컴퓨터에서 같은 데이터를 공유합니다.";
  if (remoteLoading) return "Supabase DB에서 데이터를 불러오는 중입니다.";
  if (remoteError) return "Supabase 연결 오류: " + remoteError + " 설정값과 테이블을 확인해주세요.";
  if (EDGE_ENABLED && remoteReady) return "Supabase Auth + Edge Function 보안 모드 연결됨: 관리자/컨설턴트 권한을 서버에서 확인합니다.";
  if (remoteReady) return "Supabase DB 연결됨: 신청자와 관리자 수정 내용이 연결된 DB에 저장됩니다.";
  return "Supabase 설정이 감지되었습니다. 저장 시 DB에 동기화됩니다.";
}
function renderAdmin(tab = "applications") {
  if (!currentUser()) return renderLogin();
  const adminMode = isAdmin();
  const tabs = adminMode ? [["applications","상담 신청"],["content","기본 내용"],["menus","메뉴 내용"],["images","배너/이미지"],["boards","게시판"],["users","계정관리"],["password","비밀번호 변경"]] : [["applications","상담 신청"],["password","비밀번호 변경"]];
  const active = tabs.some((item) => item[0] === tab) ? tab : "applications";
  shell("관리자", '<main class="admin-shell"><div class="admin-topbar"><h1>' + h(currentUser().name) + ' 관리 페이지</h1><div class="admin-actions"><a class="btn ghost" href="#/">사이트 보기</a><button class="btn ghost" type="button" data-reset>초기화</button><a class="btn ghost" href="#/logout">로그아웃</a></div></div><p class="static-admin-note">' + h(adminStorageNote()) + '</p><div class="admin-tabs">' + tabs.map((item) => '<button class="' + (item[0] === active ? "active" : "") + '" data-admin-tab="' + item[0] + '">' + item[1] + '</button>').join("") + '</div><section id="adminPanel"></section></main>');
  document.querySelectorAll("[data-admin-tab]").forEach((button) => button.addEventListener("click", () => renderAdmin(button.dataset.adminTab)));
  document.querySelector("[data-reset]").addEventListener("click", () => {
    if (!confirm("현재 브라우저에 저장된 정적 HTML 데이터를 초기화할까요?")) return;
    localStorage.removeItem(KEY_SITE); localStorage.removeItem(KEY_USERS); localStorage.removeItem(KEY_APPLICATIONS); localStorage.removeItem(KEY_SESSION);
    site = clone(INITIAL_SITE); users = clone(INITIAL_USERS); applications = clone(INITIAL_APPLICATIONS); session = null;
    setRoute("/");
  });
  if (active === "applications") renderAdminApplications();
  if (active === "content") renderAdminContent();
  if (active === "menus") renderAdminMenus();
  if (active === "images") renderAdminImages();
  if (active === "boards") renderAdminBoards();
  if (active === "users") renderAdminUsers();
  if (active === "password") renderAdminPassword();
}
function renderAdminApplications(loaded = false) {
  if (EDGE_ENABLED && !loaded) {
    document.getElementById("adminPanel").innerHTML = '<div class="admin-card"><p>신청 내역을 불러오는 중입니다.</p></div>';
    refreshApplicationsFromRemote().then(() => renderAdminApplications(true)).catch((error) => {
      document.getElementById("adminPanel").innerHTML = '<div class="admin-card"><p class="message error">' + h(error.message || "신청 내역을 불러오지 못했습니다.") + '</p></div>';
    });
    return;
  }
  const list = applicationsForCurrentUser();
  const rows = list.map((item) => '<tr><td>' + h(shortDate(item.createdAt)) + '</td><td>' + h(item.status) + '</td><td>' + h(item.consultantName) + '</td><td>' + h(item.date + " " + item.time) + '</td><td>' + h(item.school) + '</td><td>' + h(item.grade) + '</td><td>' + h(item.studentName) + '</td><td>' + h(item.applicantType) + '</td><td>' + (isAdmin() ? '<button class="btn ghost" data-delete-app="' + h(item.id) + '">삭제</button>' : "") + '</td></tr>').join("");
  document.getElementById("adminPanel").innerHTML = '<div class="metric-row"><div class="metric"><span>전체</span><strong>' + list.length + '</strong></div><div class="metric"><span>접수</span><strong>' + list.filter((item) => item.status === "접수").length + '</strong></div><div class="metric"><span>확정</span><strong>' + list.filter((item) => item.status === "확정").length + '</strong></div><div class="metric"><span>취소</span><strong>' + list.filter((item) => item.status === "취소").length + '</strong></div></div><div class="static-mini-actions"><button class="btn" data-export>엑셀 다운로드</button></div><div class="table-wrap"><table class="admin-table"><thead><tr><th>신청일</th><th>상태</th><th>컨설턴트</th><th>날짜/시간</th><th>학교</th><th>학년</th><th>학생</th><th>신청자</th><th></th></tr></thead><tbody>' + rows + '</tbody></table></div>';
  document.querySelector("[data-export]").addEventListener("click", exportApplications);
  document.querySelectorAll("[data-delete-app]").forEach((button) => button.addEventListener("click", async () => {
    if (EDGE_ENABLED) {
      try {
        await callEdge("deleteApplication", { id: button.dataset.deleteApp }, { auth: true });
      } catch (error) {
        alert(error.message || "삭제하지 못했습니다.");
        return;
      }
    }
    applications = applications.filter((item) => item.id !== button.dataset.deleteApp);
    if (!EDGE_ENABLED) saveApplications();
    renderAdminApplications(true);
  }));
}
function renderAdminContent() {
  document.getElementById("adminPanel").innerHTML = '<div class="admin-card"><div class="admin-grid"><div class="form-field"><label>사이트 이름</label><input id="siteName" value="' + h(site.siteName) + '"></div><div class="form-field"><label>저작권</label><input id="copyright" value="' + h(site.copyright) + '"></div><div class="form-field full"><label>푸터 주소</label><textarea id="footerAddress">' + h(site.footerAddress) + '</textarea></div><div class="form-field"><label>상담 페이지 제목</label><input id="consultingPageTitle" value="' + h(site.consulting.pageTitle || "") + '"></div><div class="form-field"><label>상담 안내 제목</label><input id="consultingNoticeTitle" value="' + h(site.consulting.noticeTitle || "") + '"></div><div class="form-field full"><label>상담 안내 부제목</label><input id="consultingNoticeSubtitle" value="' + h(site.consulting.noticeSubtitle || "") + '"></div><div class="form-field full"><label>상담 안내 내용 HTML</label><textarea id="consultingNoticeHtml">' + h(site.consulting.noticeHtml || "") + '</textarea></div></div><button class="btn" data-save-content>저장</button></div><div id="pagesEditor" class="static-editor-list">' + (site.contentPages || []).map((page, index) => '<div class="admin-card" data-page="' + index + '"><h2>' + h(page.title) + '</h2><div class="admin-grid"><div class="form-field"><label>경로</label><input data-field="path" value="' + h(page.path) + '"></div><div class="form-field"><label>상위 메뉴</label><input data-field="crumb" value="' + h(page.crumb || "") + '"></div><div class="form-field"><label>제목</label><input data-field="title" value="' + h(page.title) + '"></div><div class="form-field"><label>부제목</label><input data-field="subtitle" value="' + h(page.subtitle || "") + '"></div><div class="form-field full"><label>본문 HTML</label><textarea data-field="html">' + h(page.html || "") + '</textarea></div></div></div>').join("") + '</div><button class="btn" data-save-pages>페이지 저장</button>';
  document.querySelector("[data-save-content]").addEventListener("click", () => {
    site.siteName = document.getElementById("siteName").value.trim();
    site.copyright = document.getElementById("copyright").value.trim();
    site.footerAddress = document.getElementById("footerAddress").value;
    site.consulting.pageTitle = document.getElementById("consultingPageTitle").value.trim();
    site.consulting.noticeTitle = document.getElementById("consultingNoticeTitle").value.trim();
    site.consulting.noticeSubtitle = document.getElementById("consultingNoticeSubtitle").value.trim();
    site.consulting.noticeHtml = document.getElementById("consultingNoticeHtml").value;
    saveSite(); alert("저장되었습니다."); renderAdmin("content");
  });
  document.querySelector("[data-save-pages]").addEventListener("click", () => {
    site.contentPages = [...document.querySelectorAll("[data-page]")].map((card) => ({ path: card.querySelector('[data-field="path"]').value.trim(), crumb: card.querySelector('[data-field="crumb"]').value.trim(), title: card.querySelector('[data-field="title"]').value.trim(), subtitle: card.querySelector('[data-field="subtitle"]').value.trim(), html: card.querySelector('[data-field="html"]').value })).filter((page) => page.path && page.title);
    saveSite(); alert("저장되었습니다."); renderAdmin("content");
  });
}
function renderAdminMenus() {
  document.getElementById("adminPanel").innerHTML = '<div class="admin-card"><div class="nav-editor-head"><div><h2>상단 메뉴 이름</h2><p class="admin-help">상위 메뉴와 하위 메뉴 이름/경로를 수정합니다.</p></div><button class="btn secondary" data-add-nav>상위 메뉴 추가</button></div><div id="navEditor" class="nav-editor-list"></div><button class="btn" data-save-nav>저장</button></div>';
  const draw = () => {
    document.getElementById("navEditor").innerHTML = (site.nav || []).map((item, index) => '<div class="nav-edit-card" data-nav="' + index + '"><div class="nav-edit-head"><h3>상위 메뉴 ' + (index + 1) + '</h3><div class="nav-edit-actions"><button class="btn ghost" data-add-child="' + index + '">하위 메뉴 추가</button><button class="btn ghost" data-remove-nav="' + index + '">상위 메뉴 삭제</button></div></div><div class="admin-grid nav-grid"><div class="form-field"><label>상위 메뉴명</label><input data-title value="' + h(item.title) + '"></div><div class="form-field"><label>연결 경로</label><input data-href value="' + h(item.href) + '"></div></div><div class="nav-child-list">' + (item.children || []).map((child, childIndex) => '<div class="nav-child-row" data-child="' + childIndex + '"><div class="form-field"><label>하위 메뉴명</label><input data-child-title value="' + h(child.title) + '"></div><div class="form-field"><label>연결 경로</label><input data-child-href value="' + h(child.href) + '"></div><button class="btn ghost" data-remove-child="' + index + ':' + childIndex + '">삭제</button></div>').join("") + '</div></div>').join("");
  };
  const collect = () => {
    site.nav = [...document.querySelectorAll("[data-nav]")].map((card) => ({ title: card.querySelector("[data-title]").value.trim(), href: card.querySelector("[data-href]").value.trim() || "#", children: [...card.querySelectorAll("[data-child]")].map((row) => ({ title: row.querySelector("[data-child-title]").value.trim(), href: row.querySelector("[data-child-href]").value.trim() || "#" })).filter((child) => child.title) })).filter((item) => item.title);
  };
  draw();
  document.getElementById("adminPanel").addEventListener("click", (event) => {
    if (event.target.matches("[data-add-nav]")) { collect(); site.nav.push({ title: "새 메뉴", href: "#", children: [] }); draw(); }
    if (event.target.matches("[data-remove-nav]")) { collect(); site.nav.splice(Number(event.target.dataset.removeNav), 1); draw(); }
    if (event.target.matches("[data-add-child]")) { collect(); const i = Number(event.target.dataset.addChild); site.nav[i].children.push({ title: "새 하위 메뉴", href: "#" }); draw(); }
    if (event.target.matches("[data-remove-child]")) { collect(); const [i, j] = event.target.dataset.removeChild.split(":").map(Number); site.nav[i].children.splice(j, 1); draw(); }
    if (event.target.matches("[data-save-nav]")) { collect(); saveSite(); alert("저장되었습니다."); renderAdmin("menus"); }
  });
}
function readFileData(input, callback) {
  const file = input.files?.[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = () => callback(reader.result);
  reader.readAsDataURL(file);
}
function renderAdminImages() {
  document.getElementById("adminPanel").innerHTML = '<div class="admin-card"><h2>로고/배너</h2><div class="admin-grid"><div class="form-field full"><label>로고</label><div class="image-preview logo-preview"><img style="display:block" src="' + h(site.logo) + '"></div><input type="file" data-image="logo"></div><div class="form-field full"><label>메인 사진</label><div class="image-preview banner-preview"><img style="display:block" src="' + h(site.home.mainBanner) + '"></div><input type="file" data-image="mainBanner"></div></div></div><div class="admin-card"><h2>팝업</h2><div class="static-mini-actions"><button class="btn secondary" data-add-popup>팝업 추가</button></div><div id="popupList" class="popup-editor-list"></div><button class="btn" data-save-popups>저장</button></div>';
  const draw = () => {
    document.getElementById("popupList").innerHTML = (site.popups || []).map((popup, index) => '<div class="admin-card popup-edit-card" data-popup-edit="' + index + '"><div class="popup-edit-head"><h3>팝업 ' + (index + 1) + '</h3><div class="popup-edit-actions"><label><input type="checkbox" data-field="enabled" ' + (popup.enabled ? "checked" : "") + '> 사용</label><button class="btn ghost" data-remove-popup="' + index + '">삭제</button></div></div><div class="admin-grid popup-grid"><div class="form-field image-field full"><label>이미지</label><div class="image-preview popup-preview"><img style="display:block" src="' + h(popup.image || "") + '"></div><input type="file" data-popup-image="' + index + '"></div><div class="form-field"><label>왼쪽 위치</label><input type="number" data-field="left" value="' + h(popup.left) + '"></div><div class="form-field"><label>위쪽 위치</label><input type="number" data-field="top" value="' + h(popup.top) + '"></div><div class="form-field"><label>가로</label><input type="number" data-field="width" value="' + h(popup.width) + '"></div><div class="form-field"><label>세로</label><input type="number" data-field="height" value="' + h(popup.height) + '"></div></div></div>').join("");
  };
  const collect = () => {
    site.popups = [...document.querySelectorAll("[data-popup-edit]")].map((card, index) => ({ ...site.popups[index], id: site.popups[index]?.id || "popup" + (index + 1), enabled: card.querySelector('[data-field="enabled"]').checked, left: Number(card.querySelector('[data-field="left"]').value) || 0, top: Number(card.querySelector('[data-field="top"]').value) || 0, width: Number(card.querySelector('[data-field="width"]').value) || 450, height: Number(card.querySelector('[data-field="height"]').value) || 800 }));
  };
  draw();
  document.querySelector('[data-image="logo"]').addEventListener("change", (event) => readFileData(event.target, (data) => { site.logo = data; saveSite(); renderAdminImages(); }));
  document.querySelector('[data-image="mainBanner"]').addEventListener("change", (event) => readFileData(event.target, (data) => { site.home.mainBanner = data; saveSite(); renderAdminImages(); }));
  document.getElementById("adminPanel").addEventListener("change", (event) => {
    if (event.target.matches("[data-popup-image]")) readFileData(event.target, (data) => { site.popups[Number(event.target.dataset.popupImage)].image = data; saveSite(); renderAdminImages(); });
  });
  document.getElementById("adminPanel").addEventListener("click", (event) => {
    if (event.target.matches("[data-add-popup]")) { collect(); site.popups.push({ id: "popup" + (site.popups.length + 1), enabled: true, image: "", left: 10, top: 10, width: 450, height: 800 }); draw(); }
    if (event.target.matches("[data-remove-popup]")) { collect(); site.popups.splice(Number(event.target.dataset.removePopup), 1); draw(); }
    if (event.target.matches("[data-save-popups]")) { collect(); saveSite(); alert("저장되었습니다."); renderAdminImages(); }
  });
}
function renderAdminBoards() {
  document.getElementById("adminPanel").innerHTML = '<div class="static-editor-list">' + (site.boards || []).map((board, index) => '<div class="admin-card" data-board="' + index + '"><h2>' + h(board.title) + '</h2><div class="admin-grid"><div class="form-field"><label>경로</label><input data-field="path" value="' + h(board.path) + '"></div><div class="form-field"><label>제목</label><input data-field="title" value="' + h(board.title) + '"></div><div class="form-field full"><label>설명</label><input data-field="description" value="' + h(board.description || "") + '"></div><div class="form-field full"><label>게시물: 제목|날짜|본문 HTML</label><textarea data-field="items">' + h((board.items || []).map((item) => [item.title || "", item.date || "", item.html || ""].join("|")).join("\n")) + '</textarea></div></div></div>').join("") + '</div><button class="btn" data-save-boards>저장</button>';
  document.querySelector("[data-save-boards]").addEventListener("click", () => {
    site.boards = [...document.querySelectorAll("[data-board]")].map((card, index) => ({ ...site.boards[index], path: card.querySelector('[data-field="path"]').value.trim(), title: card.querySelector('[data-field="title"]').value.trim(), description: card.querySelector('[data-field="description"]').value.trim(), items: card.querySelector('[data-field="items"]').value.split("\n").map((line) => { const [title, date, html = ""] = line.split("|"); return { title: (title || "").trim(), date: (date || "").trim(), html: html.trim() }; }).filter((item) => item.title) }));
    saveSite(); alert("저장되었습니다."); renderAdmin("boards");
  });
}
function renderAdminUsers(loaded = false) {
  if (EDGE_ENABLED && isAdmin() && !loaded) {
    document.getElementById("adminPanel").innerHTML = '<div class="admin-card"><p>계정 목록을 불러오는 중입니다.</p></div>';
    callEdge("listUsers", {}, { auth: true }).then((data) => {
      users = data.users || users;
      saveJson(KEY_USERS, users);
      renderAdminUsers(true);
    }).catch((error) => {
      document.getElementById("adminPanel").innerHTML = '<div class="admin-card"><p class="message error">' + h(error.message || "계정 목록을 불러오지 못했습니다.") + '</p></div>';
    });
    return;
  }
  document.getElementById("adminPanel").innerHTML = '<div class="admin-card"><h2>계정관리</h2><p class="admin-help">' + (EDGE_ENABLED ? '비밀번호는 표시되지 않습니다. 새 비밀번호를 입력한 행만 Supabase Auth에 반영됩니다.' : '컨설턴트 아이디와 비밀번호를 관리합니다.') + '</p><div class="static-mini-actions"><button class="btn secondary" data-add-user>컨설턴트 추가</button></div><div class="table-wrap"><table class="admin-table"><thead><tr><th>아이디</th><th>이름</th><th>권한</th><th>새 비밀번호</th><th></th></tr></thead><tbody>' + users.map((user, index) => '<tr data-user="' + index + '"><td><input data-field="id" value="' + h(user.id) + '" ' + (user.id === "admin" ? "readonly" : "") + '><input type="hidden" data-field="authUserId" value="' + h(user.authUserId || "") + '"></td><td><input data-field="name" value="' + h(user.name) + '"></td><td><select data-field="role"><option value="admin" ' + (user.role === "admin" ? "selected" : "") + '>관리자</option><option value="consultant" ' + (user.role === "consultant" ? "selected" : "") + '>컨설턴트</option></select></td><td><input data-field="password" type="password" placeholder="' + (EDGE_ENABLED ? "비워두면 유지" : "") + '" value="' + h(EDGE_ENABLED ? "" : user.password) + '"></td><td>' + (user.id === "admin" ? "" : '<button class="btn ghost" data-remove-user="' + index + '">삭제</button>') + '</td></tr>').join("") + '</tbody></table></div><button class="btn" data-save-users>저장</button></div>';
  document.getElementById("adminPanel").addEventListener("click", (event) => {
    if (event.target.matches("[data-add-user]")) { users.push({ id: "consultant" + (users.length + 1), name: "새 컨설턴트", role: "consultant", password: "0000" }); renderAdminUsers(true); }
    if (event.target.matches("[data-remove-user]")) { users.splice(Number(event.target.dataset.removeUser), 1); saveUsers(); renderAdminUsers(true); }
    if (event.target.matches("[data-save-users]")) {
      users = [...document.querySelectorAll("[data-user]")].map((row) => ({ id: row.querySelector('[data-field="id"]').value.trim(), authUserId: row.querySelector('[data-field="authUserId"]').value.trim(), name: row.querySelector('[data-field="name"]').value.trim(), role: row.querySelector('[data-field="role"]').value, password: row.querySelector('[data-field="password"]').value }));
      site.form.consultants = users.filter((user) => user.role === "consultant").map((user) => ({ id: user.id, name: user.name }));
      saveUsers(); saveSite(); alert("저장되었습니다."); renderAdminUsers(true);
    }
  });
}
function renderAdminPassword() {
  document.getElementById("adminPanel").innerHTML = '<div class="admin-card"><h2>비밀번호 변경</h2><div class="admin-grid"><div class="form-field"><label>현재 비밀번호</label><input id="oldPw" type="password"></div><div class="form-field"><label>새 비밀번호</label><input id="newPw" type="password"></div></div><p class="message" id="pwMsg"></p><button class="btn" data-save-password>변경</button></div>';
  document.querySelector("[data-save-password]").addEventListener("click", async () => {
    const user = currentUser();
    if (EDGE_ENABLED) {
      try {
        await signInWithSupabaseAuth(user.id, document.getElementById("oldPw").value);
        await callEdge("changePassword", { password: document.getElementById("newPw").value }, { auth: true });
        document.getElementById("pwMsg").className = "message";
        document.getElementById("pwMsg").textContent = "변경되었습니다. 다음 로그인부터 새 비밀번호를 사용하세요.";
      } catch (error) {
        document.getElementById("pwMsg").className = "message error";
        document.getElementById("pwMsg").textContent = error.message || "비밀번호를 변경하지 못했습니다.";
      }
      return;
    }
    const actual = users.find((item) => item.id === user.id);
    if (actual.password !== document.getElementById("oldPw").value) { document.getElementById("pwMsg").className = "message error"; document.getElementById("pwMsg").textContent = "현재 비밀번호가 일치하지 않습니다."; return; }
    actual.password = document.getElementById("newPw").value;
    saveUsers();
    document.getElementById("pwMsg").className = "message";
    document.getElementById("pwMsg").textContent = "변경되었습니다.";
  });
}

function exportApplications() {
  const list = applicationsForCurrentUser();
  const headers = ["신청일","프로그램","상태","컨설턴트","장소","날짜/시간","거주지","학부모연락처","학생이름","학생연락처","학교명","학년","상담희망내용"];
  const rows = list.map((item) => [item.createdAt, item.programTitle, item.status, item.consultantName, item.place, item.date + " " + item.time, item.residence, item.parentPhone, item.studentName, item.studentPhone, item.school, item.grade, item.content]);
  const html = '<html><head><meta charset="utf-8"></head><body><table><tr>' + headers.map((item) => '<td>' + h(item) + '</td>').join("") + '</tr>' + rows.map((row) => '<tr>' + row.map((cell) => '<td>' + h(cell || "") + '</td>').join("") + '</tr>').join("") + '</table></body></html>';
  const blob = new Blob([html], { type: "application/vnd.ms-excel;charset=utf-8" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = "gijang-applications.xls";
  a.click();
  URL.revokeObjectURL(url);
}
function renderBoardList(board) {
  const rows = (board.items || []).map((item, index) => '<a class="board-row" href="#' + normalizePath(board.path) + '/view/' + index + '"><span class="board-title">' + h(item.title) + '</span><span class="board-date">' + h(item.date || "") + '</span></a>').join("") || '<div class="notice-empty">등록된 게시물이 없습니다.</div>';
  shell(board.title, renderRealPageHead(board.title, [board.crumb || "열린마당"]) + '<main class="subpage-wrap"><section class="board-page"><div class="board-head"><p>' + h(board.description || "") + '</p>' + (currentUser() ? '<a class="btn ghost" href="#/admin">게시판 수정</a>' : "") + '</div><div class="board-list">' + rows + '</div></section></main>');
}
function renderBoardDetail(board, index) {
  const item = (board.items || [])[Number(index)];
  if (!item) return renderNotFound();
  shell(item.title, renderRealPageHead(board.title, [board.crumb || "열린마당"]) + '<main class="subpage-wrap"><article class="board-detail"><div class="board-detail-top"><a class="btn ghost" href="#' + board.path + '">목록</a></div><h2>' + h(item.title) + '</h2><p class="board-date">' + h(item.date || "") + '</p><div class="content-body">' + safeHtml(item.html || "") + '</div></article></main>');
}
function renderNotFound() {
  shell("준비 중", '<main class="container"><h1>준비 중</h1><p>해당 페이지는 준비 중입니다.</p></main>');
}
function route() {
  const { pathname, params } = appPath();
  if (pathname === "/logout") { session = null; saveSession(); setRoute("/"); return; }
  if (pathname === "/" || pathname === "/index.html") return renderHome();
  if (pathname === "/admin") return renderAdmin();
  if (pathname === "/04sub01/write" || pathname === "/bbs/write.php") return renderWriteForm();
  if (pathname === "/04sub01") return renderConfirmList(params.get("submitted") === "1");
  if (pathname === "/content/컨설턴트-신청확인/" || pathname === "/check") return renderLookup();
  if (pathname === "/content/11맞춤형컨설팅/" || pathname === "/consulting") return renderConsulting();
  if (pathname === "/05sub06") return renderSchedule(params.get("date") || "");
  if (pathname.startsWith("/05sub06/schedule/")) return renderScheduleDetail(pathname.split("/").pop());
  const content = (site.contentPages || []).find((page) => normalizePath(page.path) === normalizePath(pathname));
  if (content) return renderContentPage(content);
  const board = (site.boards || []).find((item) => normalizePath(item.path) === normalizePath(pathname));
  if (board) return renderBoardList(board);
  for (const item of site.boards || []) {
    const base = normalizePath(item.path) + "/view/";
    if (normalizePath(pathname).startsWith(base)) return renderBoardDetail(item, normalizePath(pathname).slice(base.length));
  }
  const writePage = (site.contentPages || []).find((page) => page.ctaHref && normalizePath(page.ctaHref) === normalizePath(pathname));
  if (writePage) return renderWriteForm(writePage);
  return renderNotFound();
}
function renderBoot() {
  document.getElementById("app").innerHTML = '<main class="login-bg"><div class="login-card"><img src="' + h(site.logo) + '" alt="' + h(site.siteName) + '"><h1>데이터 불러오는 중</h1><p class="static-muted">Supabase DB 연결을 확인하고 있습니다.</p></div></main>';
}
async function boot() {
  if (REMOTE_ENABLED) {
    renderBoot();
    await loadRemoteData();
  }
  route();
}
window.addEventListener("hashchange", route);
boot();